import scala.xml._
import scala.io.Source

case class Setting(key: String, value: String)

object ConfigService {
  def loadConfig(xmlString: String): List[Setting] = {
    val xml = XML.loadString(xmlString)
    (xml \\ "setting").map { setting =>
      Setting(
        (setting \ "key").text,
        (setting \ "value").text
      )
    }.toList
  }

  def parseConfigFromApi(): List[Setting] = {
    val apiResponse = Source.fromURL("http://your-api-url").mkString
    loadConfig(apiResponse)
  }
}